const authReducer = (state={data: null}, actions) => {
    switch(actions.type) {
        case 'AUTH':
            localStorage.setItem('Profile', JSON.stringify({...action?.data}))
            return state
            break;
        default:
            return state;
    }
}

export default authReducer
